func loadChunks(dbPath string, namespaceID *string) ([][]interface{}, *sql.DB, error) {
	db, err := sql.Open("duckdb", dbPath+"?access_mode=read_only")
	if err != nil {
		return nil, nil, fmt.Errorf("loadChunks open: %w", err)
	}
	var rows *sql.Rows
	if namespaceID != nil {
		rows, err = db.Query(
			"SELECT chunk_id, content, breadcrumb, embedding FROM embeddings WHERE embedding IS NOT NULL AND namespace = ?",
			*namespaceID,
		)
	} else {
		rows, err = db.Query(
			"SELECT chunk_id, content, breadcrumb, embedding FROM embeddings WHERE embedding IS NOT NULL",
		)
	}
	if err != nil {
		db.Close()
		return nil, nil, fmt.Errorf("loadChunks query: %w", err)
	}
	defer rows.Close()
	var result [][]interface{}
	for rows.Next() {
		var chunkID, content, breadcrumb string
		var embedding []float32
		if err := rows.Scan(&chunkID, &content, &breadcrumb, &embedding); err != nil {
			db.Close()
			return nil, nil, fmt.Errorf("loadChunks scan: %w", err)
		}
		result = append(result, []interface{}{chunkID, content, breadcrumb, embedding})
	}
	return result, db, nil
}

