    n: int,
    edges: list[tuple[int, int, float]],
    algorithm: str,
    resolution: float,
    n_iterations: int,
    seed: int | None,
) -> dict[int, int]:
    partition: dict[int, int] | None = None

    if algorithm == "leiden":
        partition = _run_leiden(n, edges, resolution, n_iterations, seed)

