		for cid, indices := range communityMembers {
			var cids []string
			for _, i := range indices {
				if i < len(chunkIDs) {
					cids = append(cids, chunkIDs[i])
				}
			}
			label, err := nerEmbeddingLabels(cids, dbPath, topLabelTerms, labelSynonymThreshold)
			if err != nil {
				return fmt.Errorf("assignLabels nerEmbeddingLabels: %w", err)
			}
			if label == "" && len(chunkTexts) > 0 {
				var texts []string
				for _, i := range indices {
					if i < len(chunkTexts) {
						texts = append(texts, chunkTexts[i])
