func loadMultilevelSchema(conn *sql.DB, instance *CommunityIndex) error {
	chunkRows, err := conn.Query("SELECT chunk_id, level, community_id FROM chunk_communities ORDER BY level")
	if err != nil {
		return fmt.Errorf("loadMultilevelSchema chunk_communities: %w", err)
	}
	defer chunkRows.Close()

	type chunkRow struct {
		chunkID  string
		level    int
		commID   int
	}
	var chunks []chunkRow
	for chunkRows.Next() {
		var r chunkRow
		if err := chunkRows.Scan(&r.chunkID, &r.level, &r.commID); err != nil {
			return fmt.Errorf("loadMultilevelSchema scan chunk: %w", err)
		}
		chunks = append(chunks, r)
	}
	chunkRows.Close()

	commRows, err := conn.Query("SELECT community_id, level, topic_label, coherence, resolution FROM communities ORDER BY level")
	if err != nil {
		return fmt.Errorf("loadMultilevelSchema communities: %w", err)
	}
	defer commRows.Close()

	type commRow struct {
		commID     int
		level      int
		label      string
		coherence  float64
		resolution float64
	}
	var comms []commRow
	for commRows.Next() {
		var r commRow
		if err := commRows.Scan(&r.commID, &r.level, &r.label, &r.coherence, &r.resolution); err != nil {
			return fmt.Errorf("loadMultilevelSchema scan community: %w", err)
		}
		comms = append(comms, r)
	}

	levelsByIdx := make(map[int]*LevelData)
	for _, r := range chunks {
		if _, ok := levelsByIdx[r.level]; !ok {
			levelsByIdx[r.level] = NewLevelData(1.0)
		}
		ld := levelsByIdx[r.level]
		ld.ChunkToCommunity[r.chunkID] = r.commID
		ld.CommunityToChunks[r.commID] = append(ld.CommunityToChunks[r.commID], r.chunkID)
	}

	for _, r := range comms {
		res := r.resolution
		if res == 0 {
			res = 1.0
		}
		if _, ok := levelsByIdx[r.level]; !ok {
			levelsByIdx[r.level] = NewLevelData(res)
		}
		ld := levelsByIdx[r.level]
		ld.Resolution = res
		if r.label != "" {
			ld.CommunityToLabel[r.commID] = r.label
		} else {
			ld.CommunityToLabel[r.commID] = ""
		}
		if r.coherence != 0 {
			ld.CommunityToCoherence[r.commID] = r.coherence
		} else {
			ld.CommunityToCoherence[r.commID] = 0.0
		}
	}

	keys := make([]int, 0, len(levelsByIdx))
	for k := range levelsByIdx {
		keys = append(keys, k)
	}
	sort.Ints(keys)
	for _, k := range keys {
		instance.levels = append(instance.levels, levelsByIdx[k])
	}
	return nil
}

