func (ci *CommunityIndex) Persist(dbPath string) error {
	db, err := sql.Open("duckdb", dbPath)
	if err != nil {
		return fmt.Errorf("CommunityIndex.Persist open: %w", err)
	}
	defer db.Close()

	for _, ddl := range []string{
		"DROP TABLE IF EXISTS chunk_communities",
		"DROP TABLE IF EXISTS communities",
		"CREATE TABLE chunk_communities (chunk_id TEXT, level INTEGER, community_id INTEGER, PRIMARY KEY (chunk_id, level))",
		"CREATE TABLE communities (community_id INTEGER, level INTEGER, topic_label TEXT, size INTEGER, coherence REAL, resolution REAL, PRIMARY KEY (community_id, level))",
	} {
		if _, err := db.Exec(ddl); err != nil {
			return fmt.Errorf("CommunityIndex.Persist DDL: %w", err)
		}
	}

	if len(ci.levels) > 0 {
		for levelIdx, ld := range ci.levels {
			for chunkID, cid := range ld.ChunkToCommunity {
				if _, err := db.Exec("INSERT INTO chunk_communities VALUES (?, ?, ?)", chunkID, levelIdx, cid); err != nil {
					return fmt.Errorf("CommunityIndex.Persist insert chunk_communities: %w", err)
				}
			}
			for cid, label := range ld.CommunityToLabel {
				size := len(ld.CommunityToChunks[cid])
				coherence := ld.CommunityToCoherence[cid]
				if _, err := db.Exec("INSERT INTO communities VALUES (?, ?, ?, ?, ?, ?)", cid, levelIdx, label, size, coherence, ld.Resolution); err != nil {
					return fmt.Errorf("CommunityIndex.Persist insert communities: %w", err)
				}
			}
		}
	} else {
		for chunkID, cid := range ci.chunkToCommunity {
			if _, err := db.Exec("INSERT INTO chunk_communities VALUES (?, ?, ?)", chunkID, 0, cid); err != nil {
				return fmt.Errorf("CommunityIndex.Persist insert flat chunk_communities: %w", err)
			}
		}
		for cid, label := range ci.communityToLabel {
			size := len(ci.communityToChunks[cid])
			coherence := ci.communityToCoherence[cid]
			if _, err := db.Exec("INSERT INTO communities VALUES (?, ?, ?, ?, ?, ?)", cid, 0, label, size, coherence, 1.0); err != nil {
				return fmt.Errorf("CommunityIndex.Persist insert flat communities: %w", err)
			}
		}
	}
	return nil
}

type SummarizeOptions struct {
	TopicLabel string
	MaxChars   int
}

func (cs *CommunitySummarizer) Summarize(
	communityID string,
	chunkTexts []string,
	opts SummarizeOptions,
) (*DocumentChunk, error) {
	if opts.MaxChars == 0 {
		opts.MaxChars = 400_000
	}
	if len(chunkTexts) == 0 {
		return nil, nil
	}
	combined := strings.Join(chunkTexts, "\n---\n")
	if len(combined) > opts.MaxChars {
		combined = combined[:opts.MaxChars]
	}
	topicLabel := opts.TopicLabel
	if topicLabel == "" {
		topicLabel = "(unlabeled)"
	}
	prompt := cs.system + "\n\n" + fmt.Sprintf(
		cs.userTemplate,
		topicLabel,
		len(chunkTexts),
		combined,
	)
	summary, err := cs.llm.Complete(prompt)
	if err != nil {
		return nil, fmt.Errorf("Summarize llm.Complete: %w", err)
	}
	var section []string
	if opts.TopicLabel != "" {
		section = []string{opts.TopicLabel}
	}
	return &DocumentChunk{
		DocumentName: fmt.Sprintf("community:%s", communityID),
		Content:      strings.TrimSpace(summary),
		ChunkType:    "community_summary",
		Section:      section,
	}, nil
}

func (cs *CommunitySummarizer) SummarizeAll(
	communityIndex *CommunityIndex,
	getChunkText func(string) *string,
	minChunks int,
	level *int,
) ([]*DocumentChunk, error) {
	var results []*DocumentChunk
	for _, cid := range communityIndex.CommunityIDs(level) {
		chunkIDs := communityIndex.CommunityChunks(cid, level)
		if len(chunkIDs) < minChunks {
			continue
		}
		var texts []string
		for _, cid2 := range chunkIDs {
			t := getChunkText(cid2)
			if t != nil {
				texts = append(texts, *t)
			}
		}
		if len(texts) == 0 {
			continue
		}
		label := communityIndex.TopicLabelForCommunity(cid, level)
		var docCommunityID string
		if level != nil {
			docCommunityID = fmt.Sprintf("%d:%d", *level, cid)
		} else {
			docCommunityID = fmt.Sprintf("%d", cid)
		}
		chunk, err := cs.Summarize(docCommunityID, texts, SummarizeOptions{TopicLabel: label})
		if err != nil {
			return nil, fmt.Errorf("SummarizeAll: %w", err)
		}
		if chunk != nil {
			results = append(results, chunk)
		}
	}
	return results, nil
}

func (s *ScoringMixin) SelectCohort(
	candidates []*ScoredChunk,
	queryEmbedding []float32,
	k int,
) []*ScoredChunk {
	if len(candidates) == 0 {
		return nil
	}

	dim := len(queryEmbedding)
	qnorm := vecNorm(queryEmbedding)
	qUnit := make([]float32, dim)
	if qnorm > 0 {
		for i, v := range queryEmbedding {
			qUnit[i] = v / qnorm
		}
	} else {
		copy(qUnit, queryEmbedding)
	}

	units := make([][]float32, len(candidates))
	relevances := make([]float64, len(candidates))

	for i, sc := range candidates {
		raw := s.getEmbedding(sc.ChunkID)
		if raw != nil && len(raw) == dim {
			norm := vecNorm(raw)
			unit := make([]float32, dim)
			if norm > 0 {
				for j, v := range raw {
					unit[j] = v / norm
				}
			} else {
				copy(unit, raw)
			}
			units[i] = unit
			relevances[i] = float64(vecDot(qUnit, unit))
		} else {
			units[i] = nil
			relevances[i] = 0.0
		}
	}

	remaining := make([]int, len(candidates))
	for i := range remaining {
		remaining[i] = i
	}
	var selUnits [][]float32
	var result []*ScoredChunk

	target := k
	if len(remaining) < target {
		target = len(remaining)
	}
	for iter := 0; iter < target; iter++ {
		bestScore := math.Inf(-1)
		bestJ := 0

		for j, i := range remaining {
			rel := relevances[i]
			pri := s.getPriority(candidates[i].Provenance)
			unit := units[i]

			var coverage float64
			if len(selUnits) > 0 {
				var maxSim float64
				if unit != nil {
					for _, su := range selUnits {
						sim := float64(vecDot(su, unit))
						if sim > maxSim {
							maxSim = sim
						}
					}
				}
				coverage = rel - s.lambda*maxSim
			} else {
				coverage = rel
			}

			composite := s.rw*rel + s.pw*pri + s.cw*coverage
			if composite > bestScore {
				bestScore = composite
				bestJ = j
			}
		}

		chosenI := remaining[bestJ]
		remaining = append(remaining[:bestJ], remaining[bestJ+1:]...)
		sc := candidates[chosenI]
		sc.Score = bestScore
		sc.Embedding = nil
		if units[chosenI] != nil {
			selUnits = append(selUnits, units[chosenI])
		} else {
			selUnits = append(selUnits, make([]float32, dim))
		}
		result = append(result, sc)
	}
	return result
}

