func (s *Store) DeleteDomain(domainID string) (int, error) {
	conn := s.vector.Conn()

	var countBefore int
	if err := conn.QueryRow("SELECT COUNT(*) FROM embeddings WHERE domain_id = ?", domainID).Scan(&countBefore); err != nil {
		return 0, fmt.Errorf("DeleteDomain count: %w", err)
	}

	rows, err := conn.Query("SELECT chunk_id FROM embeddings WHERE domain_id = ?", domainID)
	if err != nil {
		return 0, fmt.Errorf("DeleteDomain select chunk_ids: %w", err)
	}
	defer rows.Close()

	var chunkIDs []string
	for rows.Next() {
		var cid string
		if err := rows.Scan(&cid); err != nil {
			return 0, fmt.Errorf("DeleteDomain scan: %w", err)
		}
		chunkIDs = append(chunkIDs, cid)
	}
	rows.Close()

	if len(chunkIDs) > 0 {
		placeholders := strings.Repeat("?,", len(chunkIDs))
		placeholders = placeholders[:len(placeholders)-1]
		args := make([]interface{}, len(chunkIDs))
		for i, id := range chunkIDs {
			args[i] = id
		}
		if _, err := conn.Exec(fmt.Sprintf("DELETE FROM chunk_entities WHERE chunk_id IN (%s)", placeholders), args...); err != nil {
			log.Printf("DELETE chunk_entities failed: %v", err)
			return 0, fmt.Errorf("DeleteDomain chunk_entities: %w", err)
		}
		if _, err := conn.Exec(fmt.Sprintf("DELETE FROM svo_triples WHERE chunk_id IN (%s)", placeholders), args...); err != nil {
			log.Printf("DELETE svo_triples failed: %v", err)
			return 0, fmt.Errorf("DeleteDomain svo_triples: %w", err)
		}
	}

	if _, err := conn.Exec("DELETE FROM embeddings WHERE domain_id = ?", domainID); err != nil {
		return 0, fmt.Errorf("DeleteDomain embeddings: %w", err)
	}
	s.vector.SetFtsDirty(true)
	return countBefore, nil
}

