func (s *Store) NamespaceCacheValid(namespaceID string) (bool, error) {
	conn := s.vector.Conn()

	var dummy int
	nsErr := conn.QueryRow("SELECT 1 FROM namespaces WHERE namespace_id = ?", namespaceID).Scan(&dummy)
	if nsErr == sql.ErrNoRows {
		return false, nil
	}
	if nsErr != nil {
		return false, fmt.Errorf("NamespaceCacheValid ns check: %w", nsErr)
	}

	rows, err := conn.Query(`
		SELECT s.uri, s.last_crawled
		FROM sources s
		JOIN domains d ON s.domain_id = d.domain_id
		WHERE d.namespace_id = ?`, namespaceID)
	if err != nil {
		return false, fmt.Errorf("NamespaceCacheValid sources query: %w", err)
	}
	defer rows.Close()

	type sourceRow struct {
		uri         string
		lastCrawled *time.Time
	}
	var sources []sourceRow
	for rows.Next() {
		var r sourceRow
		if err := rows.Scan(&r.uri, &r.lastCrawled); err != nil {
			return false, fmt.Errorf("NamespaceCacheValid scan: %w", err)
		}
		sources = append(sources, r)
	}
	if len(sources) == 0 {
		return false, nil
	}

	remoteSchemes := []string{"http://", "https://", "github://", "s3://", "ftp://", "sftp://"}
	for _, src := range sources {
		if src.lastCrawled == nil {
			return false, nil
		}
		isRemote := false
		for _, prefix := range remoteSchemes {
			if strings.HasPrefix(src.uri, prefix) {
				isRemote = true
				break
			}
		}
		if !isRemote {
			info, err := os.Stat(src.uri)
			if err != nil {
				return false, nil
			}
			if info.ModTime().After(*src.lastCrawled) {
				return false, nil
			}
		}
	}

	var chunkCount int
	if err := conn.QueryRow("SELECT COUNT(*) FROM embeddings WHERE namespace = ?", namespaceID).Scan(&chunkCount); err != nil {
		return false, fmt.Errorf("NamespaceCacheValid chunk count: %w", err)
	}
	return chunkCount > 0, nil
}
